import { useCallback, useState } from 'react';
import {
  DndContext,
  DragOverlay,
  PointerSensor,
  KeyboardSensor,
  useSensor,
  useSensors,
  type DragEndEvent,
  type DragStartEvent,
} from '@dnd-kit/core';
import { sortableKeyboardCoordinates } from '@dnd-kit/sortable';
import type { FormSchema, FormFieldType, FormFieldDefinition } from '@/lib/form-builder-types/types';
import { BuilderProvider, useFormBuilder } from './builder-context';
import { FieldPalette, PaletteOverlayItem } from './field-palette';
import { Canvas } from './canvas';
import { CanvasFieldOverlay } from './canvas-field';
import { FieldSettingsPanel } from './field-settings-panel';
import { localizeText } from '@/lib/form-builder-types/i18n';

export type FormBuilderProps = {
  initialSchema?: FormSchema;
  onChange?: (schema: FormSchema) => void;
  locale: string;
  baseLocale?: string;
  availableLocales?: string[];
  className?: string;
};

type ActiveDrag = { source: 'palette'; fieldType: FormFieldType } | { source: 'canvas'; field: FormFieldDefinition };

const BuilderInner = ({
  locale,
  availableLocales,
  className,
}: {
  locale: string;
  availableLocales?: string[];
  className?: string;
}) => {
  const { addField, reorderFields } = useFormBuilder();
  const [activeDrag, setActiveDrag] = useState<ActiveDrag | null>(null);

  const sensors = useSensors(
    useSensor(PointerSensor, { activationConstraint: { distance: 5 } }),
    useSensor(KeyboardSensor, { coordinateGetter: sortableKeyboardCoordinates }),
  );

  const handleDragStart = useCallback((event: DragStartEvent) => {
    const { active } = event;
    const data = active.data.current;

    if (data?.source === 'palette') {
      setActiveDrag({ source: 'palette', fieldType: data.fieldType });
    } else if (data?.source === 'canvas') {
      setActiveDrag({ source: 'canvas', field: data.field });
    }
  }, []);

  const handleDragEnd = useCallback(
    (event: DragEndEvent) => {
      setActiveDrag(null);
      const { active, over } = event;
      if (!over) return;

      const source = active.data.current?.source;

      if (source === 'palette') {
        const fieldType = active.data.current?.fieldType as FormFieldType;
        addField(fieldType);
      } else if (source === 'canvas' && active.id !== over.id) {
        reorderFields(String(active.id), String(over.id));
      }
    },
    [addField, reorderFields],
  );

  const handleDragCancel = useCallback(() => {
    setActiveDrag(null);
  }, []);

  return (
    <div
      className={`bg-background text-foreground border-border flex h-full flex-col overflow-hidden rounded-lg border ${className ?? ''}`}
      data-testid="form-builder"
    >
      <div className="flex min-h-0 flex-1">
        <DndContext
          sensors={sensors}
          onDragStart={handleDragStart}
          onDragEnd={handleDragEnd}
          onDragCancel={handleDragCancel}
        >
          <FieldPalette />
          <Canvas locale={locale} />
          <DragOverlay dropAnimation={null}>
            {activeDrag?.source === 'palette' && <PaletteOverlayItem fieldType={activeDrag.fieldType} />}
            {activeDrag?.source === 'canvas' && (
              <CanvasFieldOverlay
                label={localizeText(activeDrag.field.label, locale) || activeDrag.field.type}
                type={activeDrag.field.type}
                required={activeDrag.field.required}
              />
            )}
          </DragOverlay>
        </DndContext>
        <FieldSettingsPanel locale={locale} availableLocales={availableLocales} />
      </div>
    </div>
  );
};

export const FormBuilder: React.FC<FormBuilderProps> = ({
  initialSchema,
  onChange,
  locale,
  availableLocales,
  className,
}) => {
  return (
    <BuilderProvider initialSchema={initialSchema} onChange={onChange}>
      <BuilderInner locale={locale} availableLocales={availableLocales} className={className} />
    </BuilderProvider>
  );
};

import { createContext, useContext, useReducer, useCallback, useEffect, type ReactNode } from 'react';
import { nanoid } from 'nanoid';
import type { FormSchema, FormFieldDefinition, FormFieldType } from '@/lib/form-builder-types/types';
import { FIELD_TYPE_META } from './field-palette';

type BuilderState = {
  schema: FormSchema;
  selectedFieldId: string | null;
};

type BuilderAction =
  | { type: 'ADD_FIELD'; payload: { fieldType: FormFieldType; index?: number } }
  | { type: 'REMOVE_FIELD'; payload: { fieldId: string } }
  | { type: 'UPDATE_FIELD'; payload: { fieldId: string; updates: Partial<FormFieldDefinition> } }
  | { type: 'REORDER_FIELDS'; payload: { activeId: string; overId: string } }
  | { type: 'SELECT_FIELD'; payload: { fieldId: string | null } }
  | { type: 'UPDATE_SCHEMA'; payload: Partial<FormSchema> };

const createDefaultField = (fieldType: FormFieldType, order: number): FormFieldDefinition => ({
  id: nanoid(8),
  type: fieldType,
  label: { 'en-US': FIELD_TYPE_META[fieldType]?.label ?? fieldType },
  order,
  required: false,
});

const builderReducer = (state: BuilderState, action: BuilderAction): BuilderState => {
  switch (action.type) {
    case 'ADD_FIELD': {
      const { fieldType, index } = action.payload;
      const newField = createDefaultField(fieldType, index ?? state.schema.fields.length);

      const fields = [...state.schema.fields];
      if (index !== undefined) {
        fields.splice(index, 0, newField);
        // Recalculate order
        fields.forEach((f, i) => (f.order = i));
      } else {
        fields.push(newField);
      }

      return {
        ...state,
        schema: { ...state.schema, fields },
        selectedFieldId: newField.id,
      };
    }

    case 'REMOVE_FIELD': {
      const fields = state.schema.fields
        .filter((f) => f.id !== action.payload.fieldId)
        .map((f, i) => ({ ...f, order: i }));

      return {
        ...state,
        schema: { ...state.schema, fields },
        selectedFieldId: state.selectedFieldId === action.payload.fieldId ? null : state.selectedFieldId,
      };
    }

    case 'UPDATE_FIELD': {
      const { fieldId, updates } = action.payload;
      const fields = state.schema.fields.map((f) => (f.id === fieldId ? { ...f, ...updates } : f));

      return {
        ...state,
        schema: { ...state.schema, fields },
      };
    }

    case 'REORDER_FIELDS': {
      const { activeId, overId } = action.payload;
      const fields = [...state.schema.fields];
      const activeIndex = fields.findIndex((f) => f.id === activeId);
      const overIndex = fields.findIndex((f) => f.id === overId);

      if (activeIndex === -1 || overIndex === -1) return state;

      const [moved] = fields.splice(activeIndex, 1);
      if (!moved) return state;
      fields.splice(overIndex, 0, moved);
      fields.forEach((f, i) => (f.order = i));

      return {
        ...state,
        schema: { ...state.schema, fields },
      };
    }

    case 'SELECT_FIELD':
      return { ...state, selectedFieldId: action.payload.fieldId };

    case 'UPDATE_SCHEMA':
      return {
        ...state,
        schema: { ...state.schema, ...action.payload },
      };

    default:
      return state;
  }
};

type BuilderContextValue = {
  state: BuilderState;
  addField: (fieldType: FormFieldType, index?: number) => void;
  removeField: (fieldId: string) => void;
  updateField: (fieldId: string, updates: Partial<FormFieldDefinition>) => void;
  reorderFields: (activeId: string, overId: string) => void;
  selectField: (fieldId: string | null) => void;
  updateSchema: (updates: Partial<FormSchema>) => void;
  selectedField: FormFieldDefinition | undefined;
};

const BuilderContext = createContext<BuilderContextValue | null>(null);

export const useFormBuilder = (): BuilderContextValue => {
  const ctx = useContext(BuilderContext);
  if (!ctx) throw new Error('useFormBuilder must be used within a BuilderProvider');
  return ctx;
};

const DEFAULT_SCHEMA: FormSchema = {
  id: '',
  title: { 'en-US': 'Untitled Form' },
  fields: [],
};

export type BuilderProviderProps = {
  initialSchema?: FormSchema;
  onChange?: (schema: FormSchema) => void;
  children: ReactNode;
};

export const BuilderProvider: React.FC<BuilderProviderProps> = ({ initialSchema, onChange, children }) => {
  const [state, dispatch] = useReducer(builderReducer, {
    schema: initialSchema ?? DEFAULT_SCHEMA,
    selectedFieldId: null,
  });

  const notifyChange = useCallback((newState: BuilderState) => onChange?.(newState.schema), [onChange]);

  const addField = useCallback((fieldType: FormFieldType, index?: number) => {
    dispatch({ type: 'ADD_FIELD', payload: { fieldType, index } });
  }, []);

  const removeField = useCallback((fieldId: string) => dispatch({ type: 'REMOVE_FIELD', payload: { fieldId } }), []);

  const updateField = useCallback(
    (fieldId: string, updates: Partial<FormFieldDefinition>) =>
      dispatch({ type: 'UPDATE_FIELD', payload: { fieldId, updates } }),
    [],
  );

  const reorderFields = useCallback(
    (activeId: string, overId: string) => dispatch({ type: 'REORDER_FIELDS', payload: { activeId, overId } }),
    [],
  );

  const selectField = useCallback(
    (fieldId: string | null) => dispatch({ type: 'SELECT_FIELD', payload: { fieldId } }),
    [],
  );

  const updateSchema = useCallback(
    (updates: Partial<FormSchema>) => dispatch({ type: 'UPDATE_SCHEMA', payload: updates }),
    [],
  );

  const selectedField = state.schema.fields.find((f) => f.id === state.selectedFieldId);

  // Notify parent whenever schema changes
  useEffect(() => {
    notifyChange(state);
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [state.schema]);

  return (
    <BuilderContext.Provider
      value={{
        state,
        addField,
        removeField,
        updateField,
        reorderFields,
        selectField,
        updateSchema,
        selectedField,
      }}
    >
      {children}
    </BuilderContext.Provider>
  );
};

import { useDroppable } from '@dnd-kit/core';
import { SortableContext, verticalListSortingStrategy } from '@dnd-kit/sortable';
import { useFormBuilder } from './builder-context';
import { CanvasField } from './canvas-field';

type CanvasProps = {
  locale: string;
};

export const Canvas = ({ locale }: CanvasProps) => {
  const { state } = useFormBuilder();
  const { fields } = state.schema;
  const sortedFields = [...fields].sort((a, b) => a.order - b.order);

  const { setNodeRef } = useDroppable({ id: 'canvas' });

  return (
    <div ref={setNodeRef} className="bg-muted/40 flex-1 overflow-y-auto p-4">
      {sortedFields.length === 0 ? (
        <div className="border-border text-muted-foreground bg-background/50 flex h-full items-center justify-center rounded-lg border-2 border-dashed p-8 text-center text-sm">
          Drag fields from the palette to start building your form
        </div>
      ) : (
        <SortableContext items={sortedFields.map((f) => f.id)} strategy={verticalListSortingStrategy}>
          <div className="space-y-2">
            {sortedFields.map((field) => (
              <CanvasField key={field.id} field={field} locale={locale} />
            ))}
          </div>
        </SortableContext>
      )}
    </div>
  );
};

import { useSortable } from '@dnd-kit/sortable';
import { CSS } from '@dnd-kit/utilities';
import type { FormFieldDefinition } from '@/lib/form-builder-types/types';
import { useFormBuilder } from './builder-context';
import { localizeText } from '@/lib/form-builder-types/i18n';

export const CanvasFieldOverlay = ({ label, type, required }: { label: string; type: string; required?: boolean }) => {
  return (
    <div className="bg-card text-card-foreground border-primary cursor-grabbing rounded-lg border-2 px-4 py-3 shadow-lg">
      <div className="flex items-center gap-2">
        <span className="text-muted-foreground">⠿</span>
        <div className="flex-1">
          <div className="text-sm font-medium">
            {label}
            {required && <span className="text-destructive ml-1">*</span>}
          </div>
          <div className="text-muted-foreground text-xs">{type}</div>
        </div>
      </div>
    </div>
  );
};

type CanvasFieldProps = {
  field: FormFieldDefinition;
  locale: string;
};

export const CanvasField = ({ field, locale }: CanvasFieldProps) => {
  const { selectField, removeField, state } = useFormBuilder();
  const isSelected = state.selectedFieldId === field.id;

  const { attributes, listeners, setNodeRef, transform, transition, isDragging } = useSortable({
    id: field.id,
    data: { source: 'canvas', field },
  });

  const style = {
    transform: CSS.Transform.toString(transform),
    transition,
  };

  const label = localizeText(field.label, locale) || field.type;

  return (
    <div
      ref={setNodeRef}
      style={style}
      className={`bg-card text-card-foreground group relative rounded-lg border px-4 py-3 shadow-sm transition-all ${
        isSelected ? 'border-primary ring-primary/20 ring-2' : 'border-border hover:border-primary/40 hover:shadow-md'
      } ${isDragging ? 'opacity-50' : ''}`}
      onClick={() => selectField(field.id)}
    >
      <div className="flex items-center gap-2">
        <span
          {...attributes}
          {...listeners}
          className="text-muted-foreground hover:text-foreground cursor-grab rounded p-0.5 transition-colors"
        >
          ⠿
        </span>
        <div className="flex-1">
          <div className="text-sm font-medium">
            {label}
            {field.required && <span className="text-destructive ml-1">*</span>}
          </div>
          <div className="text-muted-foreground text-xs">{field.type}</div>
        </div>
        <button
          type="button"
          className="text-muted-foreground hover:bg-destructive/10 hover:text-destructive rounded p-1 text-xs opacity-0 transition-opacity group-hover:opacity-100"
          onClick={(e) => {
            e.stopPropagation();
            removeField(field.id);
          }}
        >
          ✕
        </button>
      </div>
    </div>
  );
};

import type { ComponentType } from 'react';
import { useDraggable } from '@dnd-kit/core';
import {
  IconLetterCase,
  IconHash,
  IconAt,
  IconPhone,
  IconSelector,
  IconCheckbox,
  IconCircleDot,
  IconCalendar,
  IconAlignLeft,
  IconPaperclip,
  IconHeading,
  IconSeparator,
  IconTextCaption,
} from '@tabler/icons-react';
import type { FormFieldType } from '@/lib/form-builder-types/types';

type FieldTypeMeta = {
  label: string;
  icon: ComponentType<{ size?: number }>;
  category: 'input' | 'display';
};

/**
 * Single source of truth for builder UI metadata per field type.
 * To add a new field type: add an entry here + a case in schema-builder.ts.
 */
export const FIELD_TYPE_META: Record<string, FieldTypeMeta> = {
  text:      { label: 'Text',      icon: IconLetterCase, category: 'input' },
  number:    { label: 'Number',    icon: IconHash,        category: 'input' },
  email:     { label: 'Email',     icon: IconAt,          category: 'input' },
  tel:       { label: 'Phone',     icon: IconPhone,       category: 'input' },
  select:    { label: 'Select',    icon: IconSelector,    category: 'input' },
  checkbox:  { label: 'Checkbox',  icon: IconCheckbox,    category: 'input' },
  radio:     { label: 'Radio',     icon: IconCircleDot,   category: 'input' },
  date:      { label: 'Date',      icon: IconCalendar,    category: 'input' },
  textarea:  { label: 'Text Area', icon: IconAlignLeft,   category: 'input' },
  file:      { label: 'File',      icon: IconPaperclip,   category: 'input' },
  heading:   { label: 'Heading',   icon: IconHeading,     category: 'display' },
  paragraph: { label: 'Paragraph', icon: IconTextCaption, category: 'display' },
  separator: { label: 'Separator', icon: IconSeparator,   category: 'display' },
};

const INPUT_FIELD_TYPES = Object.entries(FIELD_TYPE_META)
  .filter(([, m]) => m.category === 'input')
  .map(([type, m]) => ({ type: type as FormFieldType, ...m }));

const DISPLAY_FIELD_TYPES = Object.entries(FIELD_TYPE_META)
  .filter(([, m]) => m.category === 'display')
  .map(([type, m]) => ({ type: type as FormFieldType, ...m }));

export const PaletteOverlayItem = ({ fieldType }: { fieldType: string }) => {
  const meta = FIELD_TYPE_META[fieldType];
  const Icon = meta?.icon;
  const label = meta?.label ?? fieldType;

  return (
    <div className="bg-card text-card-foreground border-primary flex w-48 cursor-grabbing items-center gap-2 rounded-md border-2 px-3 py-2 text-sm shadow-lg">
      {Icon && <Icon size={16} />}
      <span>{label}</span>
    </div>
  );
};

const PaletteItem = ({
  type,
  label,
  icon: Icon,
}: {
  type: FormFieldType;
  label: string;
  icon: ComponentType<{ size?: number }>;
}) => {
  const { attributes, listeners, setNodeRef, isDragging } = useDraggable({
    id: `palette-${type}`,
    data: { source: 'palette', fieldType: type },
  });

  return (
    <div
      ref={setNodeRef}
      {...listeners}
      {...attributes}
      className={`hover:bg-sidebar-accent hover:text-sidebar-accent-foreground flex cursor-grab items-center gap-2 rounded-md px-3 py-2 text-sm transition-colors ${isDragging ? 'opacity-50' : ''}`}
    >
      <Icon size={16} />
      <span>{label}</span>
    </div>
  );
};

export const FieldPalette = () => {
  return (
    <div className="bg-sidebar text-sidebar-foreground border-sidebar-border w-48 shrink-0 overflow-y-auto border-r p-2">
      <h3 className="text-sidebar-foreground/60 mb-1 px-2 pt-1 text-xs font-semibold uppercase tracking-wider">
        Input
      </h3>
      <div className="space-y-0.5">
        {INPUT_FIELD_TYPES.map((item) => (
          <PaletteItem key={item.type} {...item} />
        ))}
      </div>
      <h3 className="text-sidebar-foreground/60 mb-1 mt-3 px-2 text-xs font-semibold uppercase tracking-wider">
        Display
      </h3>
      <div className="space-y-0.5">
        {DISPLAY_FIELD_TYPES.map((item) => (
          <PaletteItem key={item.type} {...item} />
        ))}
      </div>
    </div>
  );
};

import { useFormBuilder } from './builder-context';
import type { LocalizedString, FormFieldOption, FormFieldCondition, FormFieldConditionOperator } from '@/lib/form-builder-types/types';
import { FormFieldType, isDisplayField } from '@/lib/form-builder-types/types';
import { Input } from '@/components/ui/input';
import { Checkbox } from '@/components/ui/checkbox';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';

/** Field types that support minLength/maxLength validation. Extend when adding new string-based types. */
const STRING_LENGTH_TYPES = new Set<string>(['text', 'textarea', 'email', 'tel']);

/** Field types that support min/max validation. Extend when adding new numeric types. */
const NUMBER_RANGE_TYPES = new Set<string>(['number']);

type FieldSettingsPanelProps = {
  locale: string;
  availableLocales?: string[];
};

const LocalizedInput = ({
  value,
  locale,
  availableLocales,
  onChange,
  placeholder,
}: {
  value: LocalizedString | undefined;
  locale: string;
  availableLocales?: string[];
  onChange: (value: LocalizedString) => void;
  placeholder?: string;
}) => {
  const locales = availableLocales ?? [locale];
  const current: Record<string, string> = typeof value === 'string' ? { [locale]: value } : (value ?? {});

  return (
    <div className="space-y-1">
      {locales.map((loc) => (
        <div key={loc} className="flex items-center gap-2">
          <span className="text-sidebar-foreground/50 w-12 shrink-0 text-xs">{loc}</span>
          <Input
            value={current[loc] ?? ''}
            placeholder={placeholder}
            onChange={(e) => onChange({ ...current, [loc]: e.target.value })}
          />
        </div>
      ))}
    </div>
  );
};

const OptionsEditor = ({
  options,
  locale,
  availableLocales,
  onChange,
}: {
  options: FormFieldOption[];
  locale: string;
  availableLocales?: string[];
  onChange: (options: FormFieldOption[]) => void;
}) => {
  const addOption = () => {
    onChange([
      ...options,
      { value: `option_${options.length + 1}`, label: { [locale]: `Option ${options.length + 1}` } },
    ]);
  };

  const removeOption = (index: number) => {
    onChange(options.filter((_, i) => i !== index));
  };

  const updateOption = (index: number, updates: Partial<FormFieldOption>) => {
    onChange(options.map((opt, i) => (i === index ? { ...opt, ...updates } : opt)));
  };

  return (
    <div className="space-y-2">
      {options.map((opt, i) => (
        <div key={i} className="border-sidebar-border bg-background/50 rounded-md border p-2">
          <div className="mb-1 flex items-center gap-2">
            <Input
              value={opt.value}
              placeholder="Value"
              onChange={(e) => updateOption(i, { value: e.target.value })}
            />
            <button
              type="button"
              className="text-destructive shrink-0 text-xs hover:underline"
              onClick={() => removeOption(i)}
            >
              ✕
            </button>
          </div>
          <LocalizedInput
            value={opt.label}
            locale={locale}
            availableLocales={availableLocales}
            onChange={(label) => updateOption(i, { label })}
            placeholder="Label"
          />
        </div>
      ))}
      <button
        type="button"
        className="border-sidebar-border text-sidebar-foreground/60 hover:bg-sidebar-accent hover:text-sidebar-accent-foreground w-full rounded-md border border-dashed px-2 py-1 text-xs transition-colors"
        onClick={addOption}
      >
        + Add Option
      </button>
    </div>
  );
};

const OPERATORS: { value: FormFieldConditionOperator; label: string; hasValue: boolean }[] = [
  { value: 'eq',       label: 'equals',         hasValue: true  },
  { value: 'neq',      label: 'not equals',     hasValue: true  },
  { value: 'gt',       label: 'greater than',   hasValue: true  },
  { value: 'lt',       label: 'less than',      hasValue: true  },
  { value: 'contains', label: 'contains',       hasValue: true  },
  { value: 'empty',    label: 'is empty',       hasValue: false },
  { value: 'notEmpty', label: 'is not empty',   hasValue: false },
];

const ConditionEditor = ({
  condition,
  currentFieldId,
  onChange,
}: {
  condition: FormFieldCondition | undefined;
  currentFieldId: string;
  onChange: (condition: FormFieldCondition | undefined) => void;
}) => {
  const { state } = useFormBuilder();

  // All input fields except the current one (can't condition on itself or display fields)
  const watchableFields = state.schema.fields.filter(
    (f) => f.id !== currentFieldId && !isDisplayField(f.type),
  );

  const enabled = condition !== undefined;
  const operator = condition?.operator ?? 'eq';
  const needsValue = OPERATORS.find((o) => o.value === operator)?.hasValue ?? true;

  const toggle = () => {
    if (enabled) {
      onChange(undefined);
    } else {
      const firstField = watchableFields[0];
      if (firstField) {
        onChange({ field: firstField.id, operator: 'eq', value: '' });
      }
    }
  };

  const update = (patch: Partial<FormFieldCondition>) => {
    if (!condition) return;
    onChange({ ...condition, ...patch });
  };

  return (
    <div className="space-y-2">
      <div className="flex items-center gap-2">
        <Checkbox id="condition-enabled" checked={enabled} onCheckedChange={toggle} />
        <label htmlFor="condition-enabled" className="text-xs">
          Show only when…
        </label>
      </div>

      {enabled && (
        <div className="border-sidebar-border space-y-2 rounded-md border p-2">
          {watchableFields.length === 0 ? (
            <p className="text-sidebar-foreground/50 text-xs">
              No other input fields to condition on.
            </p>
          ) : (
            <>
              {/* Field selector */}
              <Select
                value={condition?.field ?? ''}
                onValueChange={(v) => update({ field: v })}
              >
                <SelectTrigger className="w-full text-xs">
                  <SelectValue placeholder="Select field…" />
                </SelectTrigger>
                <SelectContent>
                  {watchableFields.map((f) => {
                    const label =
                      typeof f.label === 'string'
                        ? f.label
                        : Object.values(f.label)[0] ?? f.id;
                    return (
                      <SelectItem key={f.id} value={f.id}>
                        {label}
                      </SelectItem>
                    );
                  })}
                </SelectContent>
              </Select>

              {/* Operator selector */}
              <Select
                value={operator}
                onValueChange={(v) => update({ operator: v as FormFieldConditionOperator, value: undefined })}
              >
                <SelectTrigger className="w-full text-xs">
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  {OPERATORS.map((op) => (
                    <SelectItem key={op.value} value={op.value}>
                      {op.label}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>

              {/* Value input (hidden for empty / notEmpty) */}
              {needsValue && (
                <Input
                  placeholder="Value…"
                  value={condition?.value !== undefined ? String(condition.value) : ''}
                  onChange={(e) => update({ value: e.target.value })}
                />
              )}
            </>
          )}
        </div>
      )}
    </div>
  );
};

export const FieldSettingsPanel = ({ locale, availableLocales }: FieldSettingsPanelProps) => {
  const { selectedField, updateField, state, updateSchema } = useFormBuilder();
  const { schema } = state;

  const formMetaSection = (
    <div className="border-sidebar-border border-t pt-4 space-y-4">
      <h3 className="text-sidebar-foreground/60 px-1 text-xs font-semibold uppercase tracking-wider">Form</h3>
      <div>
        <label className="mb-1 block text-xs font-medium">Title</label>
        <LocalizedInput
          value={schema.title}
          locale={locale}
          availableLocales={availableLocales}
          onChange={(title) => updateSchema({ title })}
          placeholder="Form title"
        />
      </div>
      <div>
        <label className="mb-1 block text-xs font-medium">Description</label>
        <LocalizedInput
          value={schema.description}
          locale={locale}
          availableLocales={availableLocales}
          onChange={(description) => updateSchema({ description })}
          placeholder="Optional description"
        />
      </div>
      <div>
        <label className="mb-1 block text-xs font-medium">Submit Button Label</label>
        <LocalizedInput
          value={schema.submitLabel}
          locale={locale}
          availableLocales={availableLocales}
          onChange={(submitLabel) => updateSchema({ submitLabel })}
          placeholder="Submit"
        />
      </div>
    </div>
  );

  if (!selectedField) {
    return (
      <div className="bg-sidebar text-sidebar-foreground border-sidebar-border w-64 shrink-0 flex flex-col overflow-y-auto border-l p-3 gap-4">
        <p className="text-sidebar-foreground/60 text-center text-sm mt-4">Select a field to edit its properties</p>
        <div className="flex-1" />
        {formMetaSection}
      </div>
    );
  }

  const hasOptions = selectedField.type === FormFieldType.SELECT || selectedField.type === FormFieldType.RADIO;
  const isDisplay = isDisplayField(selectedField.type);

  return (
    <div className="bg-sidebar text-sidebar-foreground border-sidebar-border w-64 shrink-0 space-y-4 overflow-y-auto border-l p-3">
      <h3 className="text-sidebar-foreground/60 px-1 text-xs font-semibold uppercase tracking-wider">Field Settings</h3>

      <div>
        <label className="mb-1 block text-xs font-medium">Type</label>
        <Select
          value={selectedField.type}
          onValueChange={(v) => updateField(selectedField.id, { type: v as FormFieldType })}
        >
          <SelectTrigger className="w-full">
            <SelectValue />
          </SelectTrigger>
          <SelectContent>
            {Object.entries(FormFieldType).map(([key, value]) => (
              <SelectItem key={value} value={value}>
                {key}
              </SelectItem>
            ))}
          </SelectContent>
        </Select>
      </div>

      <div>
        <label className="mb-1 block text-xs font-medium">
          {selectedField.type === FormFieldType.PARAGRAPH ? 'Text' : 'Label'}
        </label>
        <LocalizedInput
          value={selectedField.label}
          locale={locale}
          availableLocales={availableLocales}
          onChange={(label) => updateField(selectedField.id, { label })}
        />
      </div>

      {!isDisplay && (
        <div>
          <label className="mb-1 block text-xs font-medium">Placeholder</label>
          <LocalizedInput
            value={selectedField.placeholder}
            locale={locale}
            availableLocales={availableLocales}
            onChange={(placeholder) => updateField(selectedField.id, { placeholder })}
          />
        </div>
      )}

      {selectedField.type === FormFieldType.HEADING && (
        <div>
          <label className="mb-1 block text-xs font-medium">Description</label>
          <LocalizedInput
            value={selectedField.description}
            locale={locale}
            availableLocales={availableLocales}
            onChange={(description) => updateField(selectedField.id, { description })}
            placeholder="Optional subtitle"
          />
        </div>
      )}

      {!isDisplay && (
        <div className="flex items-center gap-2">
          <Checkbox
            id="field-required"
            checked={selectedField.required ?? false}
            onCheckedChange={(checked) => updateField(selectedField.id, { required: checked === true })}
          />
          <label htmlFor="field-required" className="text-sm">
            Required
          </label>
        </div>
      )}

      {hasOptions && (
        <div>
          <label className="mb-1 block text-xs font-medium">Options</label>
          <OptionsEditor
            options={selectedField.options ?? []}
            locale={locale}
            availableLocales={availableLocales}
            onChange={(options) => updateField(selectedField.id, { options })}
          />
        </div>
      )}

      {!isDisplay && (
        <div>
          <label className="mb-1 block text-xs font-medium">Validation</label>
          <div className="space-y-2">
            {STRING_LENGTH_TYPES.has(selectedField.type) && (
              <>
                <div className="flex items-center gap-2">
                  <span className="w-20 shrink-0 text-xs">Min Length</span>
                  <Input
                    type="number"
                    value={selectedField.validation?.minLength ?? ''}
                    onChange={(e) =>
                      updateField(selectedField.id, {
                        validation: {
                          ...selectedField.validation,
                          minLength: e.target.value ? Number(e.target.value) : undefined,
                        },
                      })
                    }
                  />
                </div>
                <div className="flex items-center gap-2">
                  <span className="w-20 shrink-0 text-xs">Max Length</span>
                  <Input
                    type="number"
                    value={selectedField.validation?.maxLength ?? ''}
                    onChange={(e) =>
                      updateField(selectedField.id, {
                        validation: {
                          ...selectedField.validation,
                          maxLength: e.target.value ? Number(e.target.value) : undefined,
                        },
                      })
                    }
                  />
                </div>
              </>
            )}
            {NUMBER_RANGE_TYPES.has(selectedField.type) && (
              <>
                <div className="flex items-center gap-2">
                  <span className="w-20 shrink-0 text-xs">Min</span>
                  <Input
                    type="number"
                    value={selectedField.validation?.min ?? ''}
                    onChange={(e) =>
                      updateField(selectedField.id, {
                        validation: {
                          ...selectedField.validation,
                          min: e.target.value ? Number(e.target.value) : undefined,
                        },
                      })
                    }
                  />
                </div>
                <div className="flex items-center gap-2">
                  <span className="w-20 shrink-0 text-xs">Max</span>
                  <Input
                    type="number"
                    value={selectedField.validation?.max ?? ''}
                    onChange={(e) =>
                      updateField(selectedField.id, {
                        validation: {
                          ...selectedField.validation,
                          max: e.target.value ? Number(e.target.value) : undefined,
                        },
                      })
                    }
                  />
                </div>
              </>
            )}
          </div>
        </div>
      )}

      {!isDisplay && (
        <div>
          <label className="mb-1 block text-xs font-medium">Condition</label>
          <ConditionEditor
            condition={selectedField.condition}
            currentFieldId={selectedField.id}
            onChange={(condition) => updateField(selectedField.id, { condition })}
          />
        </div>
      )}

      {formMetaSection}
    </div>
  );
};
